namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            new Notification { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new Notification { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new Notification { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });
    }

    /// <summary>
    /// Returns all notifications currently available.
    /// </summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>
    /// Returns only notifications with an Id greater than the given value.
    /// </summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally to generate fake data.
    /// </summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Scheduled maintenance tonight at 11 PM.",
            "Your export is ready to download.",
            "A comment was added to your thread.",
            "System update completed successfully.",
        };

        lock (_lock)
        {
            var msg = messages[_nextId % messages.Length];
            _notifications.Add(new Notification
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.UtcNow
            });
        }
    }
}

