@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @notification.Message
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR — appears in the first rendered HTML.
        notifications = NotificationService.GetAll();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is interactive (not during static SSR).
            // Start polling here so it never runs during the prerender pass.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct).ConfigureAwait(false);

            // Simulate a new notification arriving on the server side
            NotificationService.SimulateIncoming();

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(() =>
                {
                    notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

